document.getElementById('eventRegistrationForm').addEventListener('submit', function (event) {
  event.preventDefault();

  const name = document.getElementById('registrantName').value.trim();
  const email = document.getElementById('email').value.trim();
  const eventId = document.getElementById('event').value.trim(); // must be GUID
  const status = parseInt(document.getElementById('status').value, 10);
  const userid = "{{user.id}}";

  // Basic client-side validation
  const guidRegex = /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$/;
  if (!guidRegex.test(eventId)) {
    alert('Invalid Event ID. Please ensure the event value is a GUID.');
    return;
  }

  // IMPORTANT: Use exact Dataverse logical names
  const payload = {
    er_registrantname: name,         // confirm logical name
    er_email: email,                 // confirm logical name (likely all lowercase)
    er_registrationstatus: status,   // confirm this is the optionset logical name & value
    "er_RegisteredBy@odata.bind": "/contacts(" + userid +")", // entity set name (plural) + GUID
    "er_Event@odata.bind": `/er_events(${eventId})` // entity set name (plural) + GUID

  };

  webapi.safeAjax({
    type: "POST",
    url: "/_api/er_registrations", // entity set name (plural) for registrations
    contentType: "application/json; charset=utf-8",
    data: JSON.stringify(payload),
    success: function (res, status, xhr) {
      alert("Registration successful!");
      document.getElementById("eventRegistrationForm").reset();
      console.log("Entity ID:", xhr.getResponseHeader("entityID"), res);
    },
    error: function (xhr) {
      // Try to surface more diagnostic detail
      let detail = xhr.responseText;
      try {
        const j = JSON.parse(xhr.responseText);
        detail = JSON.stringify(j, null, 2);
      } catch {}
      console.error("Error creating registration:", xhr.status, detail);
      alert(`Create failed: ${xhr.status}\n${detail}`);
    }
  });
});



