<fetch version="1.0" output-format="xml-platform" mapping="logical" distinct="false">
  <entity name="er_event">
    <attribute name="er_eventid" />
    <attribute name="er_eventname" />
    <attribute name="createdon" />
    <attribute name="statuscode" />
    <attribute name="statecode" />
    <attribute name="er_seatsavalable" />
    <attribute name="overriddencreatedon" />
    <attribute name="owningbusinessunit" />
    <attribute name="ownerid" />
    <attribute name="modifiedon" />
    <attribute name="modifiedonbehalfby" />
    <attribute name="modifiedby" />
    <attribute name="er_location" />
    <attribute name="er_eventdate" />
    <attribute name="er_description" />
    <attribute name="createdonbehalfby" />
    <attribute name="createdby" />
    <order attribute="er_eventname" descending="false" />
  </entity>
</fetch>

{% endfetchxml %}

<section class="py-5">
  <div class="container">
    <div class="row">
      <div class="col-12 col-md-8 col-lg-6">
        <div class="card shadow-sm border-0 rounded-3">
          <div class="card-body">
            <h4 class="text-center mb-4">Event Registration</h4>

            <form id="eventRegistrationForm">
              <!-- Registrant Name -->
              <div class="mb-3">
                <label class="form-label">Registrant Name</label>
                <input type="text" id="registrantName" class="form-control" required />
              </div>

              <!-- Email -->
              <div class="mb-3">
                <label class="form-label">Email Address</label>
                <input type="email" id="email" class="form-control" required />
              </div>

              <!-- Event (Lookups) -->
              <div class="mb-3">
                <label class="form-label">Select Event</label>
                <select id="event" class="form-select" required>
                  <option value="" disabled selected>-- Choose Event --</option>

                  {% for result in events.results.entities %}
                  <option value="{{result.er_eventid}}">{{result.er_eventname}}</option>
                  {% endfor %}
                </select>
              </div>

              <!-- Registration Date 
              <div class="mb-3">
                <label for="registrationDate" class="form-label">Registration Date</label>
                <input type="date" id="registrationDate" name="registrationDate" class="form-control" readonly />
              </div>
-->
              <!-- Status Choice -->
              <div class="mb-4">
                <label class="form-label">Status</label>
                <select id="status" class="form-select" required>
                  <option value="0" selected>Pending</option>
                  <option value="1">Confirmed</option>
                  <option value="2">Cancelled</option>
                </select>
              </div>

              <!-- Submit -->
              <button type="submit" class="btn btn-primary px-4">Register</button>
            </form>
          </div>
        </div>
      </div>
    </div>
  </div>
</section>

{% include "WebAPI Wrapper" %}

<script>
  document.getElementById('eventRegistrationForm')
  ?.addEventListener('submit', function (e) {
    e.preventDefault();
  });
</script>
